(1, 1, 'Zero Waste Lifestyle Talk', 2, 1, '2025-10-25', '2025-10-25', '10:00:00', 'UTC-05:00', 'New York Eco Center', 'United States', 'Learn how to reduce household waste through simple daily practices.', 'online', 'talk', 'closed', 300, '2025-10-15 18:34:58', NULL),
(2, 2, 'Green Energy Workshop', 3, 1, '2025-11-05', '2025-11-05', '14:00:00', 'UTC-05:00', 'Toronto Green Hub', 'Canada', 'Hands-on workshop on solar panels, wind energy, and sustainable power.', 'physical', 'workshop', 'closed', 150, '2025-10-20 18:34:58', NULL),
(3, 3, 'Community Cleanup Day', 5, 1, '2025-11-10', '2025-11-10', '08:00:00', 'UTC+00:00', 'London Riverside Park', 'United Kingdom', 'Help clean up community spaces and reduce plastic waste.', 'physical', 'clean-up', 'open', 100, '2025-10-20 18:34:58', NULL),
(4, 4, 'Urban Tree Planting Day', 4, 1, '2025-11-15', '2025-11-15', '09:00:00', 'UTC-05:00', 'Central Park, New York', 'United States', 'Join us to plant trees and create green spaces in the city.', 'physical', 'tree-planting', 'open', 200, '2025-10-20 18:34:58', NULL),
(5, 5, 'Recycling Awareness Drive', 6, 1, '2025-11-20', '2025-11-20', '09:00:00', 'UTC+10:00', 'Sydney Community Hall', 'Australia', 'Educating the public on sorting and recycling waste effectively.', 'physical', 'workshop', 'open', 250, '2025-10-20 18:34:58', NULL),
(6, 6, 'Sustainable Startup Pitch', 6, 1, '2025-12-01', '2025-12-01', '13:00:00', 'UTC+00:00', 'Dublin Innovation Center', 'Ireland', 'Pitch your eco-friendly startup ideas to green investors.', 'hybrid', 'other', 'open', 300, '2025-10-20 18:34:58', NULL),
(7, 7, 'Eco-friendly Product Design Bootcamp', 8, 2, '2025-12-03', '2025-12-04', '09:30:00', 'UTC+12:00', 'Auckland Design Lab', 'New Zealand', 'Learn to design sustainable and reusable products in this bootcamp.', 'physical', 'workshop', 'open', 400, '2025-10-20 18:34:58', NULL),
(8, 8, 'Climate Action Seminar', 2, 1, '2025-12-10', '2025-12-10', '15:00:00', 'UTC-05:00', 'Chicago Conference Center', 'United States', 'Seminar on global climate challenges and local solutions.', 'hybrid', 'seminar', 'open', 250, '2025-10-20 18:34:58', NULL),
(9, 9, 'Sustainable Tech Hackathon', 24, 3, '2025-12-15', '2025-12-17', '08:00:00', 'UTC-05:00', 'University of Toronto', 'Canada', '48-hour hackathon building apps and devices to support sustainability.', 'physical', 'competition', 'open', 600, '2025-10-20 18:34:58', NULL),
(10, 10, 'Green Culture Festival', 8, 3, '2025-12-20', '2025-12-22', '10:00:00', 'UTC+00:00', 'Bristol Eco Center', 'United Kingdom', 'Festival celebrating sustainable living, local art, and eco-friendly food. \r\n\r\nThis event will be held for 3 days in a row, 8 hours per day from 10am to 6pm.', 'physical', 'other', 'open', 800, '2025-10-20 18:34:58', NULL),
(11, 21, 'ReLeaf Beach Clean-Up Volunteering', 6, 1, '2025-12-11', '2025-12-11', '08:00:00', 'UTC+08:00', 'East Coast Park Beach', 'Singapore', 'Join us for a community beach cleanup to protect marine life and promote sustainability. Volunteers will collect plastic, bottles, and other waste along the shoreline. Gloves and trash bags will be provided. Please wear comfortable clothing and bring water.', 'physical', 'clean-up', 'open', 50, '2025-10-20 19:31:57', '../../uploads/eventBanner/event_1760959917_68f61dad4c9e0.jpg'),
(12, 13, 'CHASE Recycling Workshop - Recycling Tips and DIY Session', 5, 1, '2025-11-29', '2025-11-29', '20:00:00', 'UTC-06:00', 'Casa De La Cultura 2 De Marzo', 'Mexico', 'Join us for an interactive recycling workshop where you’ll learn practical recycling tips and creative DIY projects using household waste. Let’s make sustainability fun and hands-on! \r\n\r\n📞Contact Us:\r\nEmail: chasewithus@gmail.com\r\nInstagram: @chaseewus', 'hybrid', 'workshop', 'open', 120, '2025-10-24 11:52:47', '../../uploads/eventBanner/event_1761277967_68faf80f0d1dc.jpg');

