INSERT INTO `tblfaq` (`faqID`, `category`, `question`, `answer`, `dateAdded`) VALUES
(1, 'General', 'What is ReLeaf?', 'ReLeaf is a sustainability-focused platform where you can share your tips and experience through blogs, join community events, and trade pre-loved or eco-friendly items securely.', '2025-10-23 14:21:12'),
(2, 'General', 'Who can use ReLeaf?', 'Anyone in the community can use ReLeaf. Whether you\'re a student, parent, worker, or retiree, ReLeaf is open for all who want to live more sustainably.', '2025-10-23 14:21:12'),
(3, 'General', 'Do I need to pay to use ReLeaf?', 'No. ReLeaf is free to join and use. There are no hidden charges for listing, browsing, or joining events.', '2025-10-23 14:21:12'),
(4, 'Blog', 'What can I post in the blog section?', 'You can share sustainability tips, personal eco-friendly experiences, DIY recycling projects, or gardening and energy-saving advice. Blogs help spread awareness and encourage others to live green.', '2025-10-23 14:21:12'),
(5, 'Event', 'What kind of events are available on ReLeaf?', 'Events include community clean-ups, gardening projects, sustainability workshops, campaigns, talks, seminars, and even competitions like hackathons.', '2025-10-23 14:21:12'),
(6, 'Event', 'How do I join an event?', 'Browse the Events section, click on an event you\'re interested in, and click Register!', '2025-10-23 14:21:12'),
(7, 'Event', 'Can I cancel my registration after I’ve registered?', 'Yes! Just go to the Events page > My Events > Search for the specific event > Select Cancel.', '2025-10-23 14:21:12'),
(8, 'Event', 'Can I host an event?', 'Yes! Go to the Events page > Host an Event > Fill in the essential information > Done! You can leave any important details relating to the event in the description, such as your social links or a Discord invite.', '2025-10-23 14:21:12'),
(9, 'Event', 'How do I manage my event?', 'Go to the Events page > My Events > Select \"Hosted Events\" > Choose the event to see the participants list. You can view, delete, or manage participants, and search for a specific one.', '2025-10-23 14:21:12'),
(10, 'Trade', 'What items can I trade on ReLeaf?', 'You can trade pre-loved items (like clothes, books, furniture) or eco-friendly products (like reusable bottles, bamboo utensils, or zero-waste tools). You can even trade plants.', '2025-10-23 14:21:12'),
(11, 'Quiz', 'Why is there a leaderboard?', 'The leaderboard encourages friendly competition among users. It motivates eco-warriors to participate in quizzes, earn points, and stay active in promoting sustainability while tracking their global rank.', '2025-10-23 14:21:12'),
(12, 'Quiz', 'Where is the quiz?', 'The Quiz button is placed on the bottom-right corner of the member’s home page.', '2025-10-23 14:21:12'),
(13, 'Quiz', 'What is the quiz for?', 'The quiz allows users to earn points, climb the leaderboard, and compete with other eco-warriors around the world by testing their environmental knowledge.', '2025-10-23 14:21:12'),
(14, 'Quiz', 'What type of quiz questions are there?', 'Questions cover topics like recycling, energy saving, sustainable shopping, green gardening, and sustainability awareness. Each stage increases in difficulty and rewards more points.', '2025-10-23 14:21:12'),
(15, 'Security', 'How does ReLeaf prevent scams?', 'ReLeaf has an active admin team, reporting tools, and secure messaging. We encourage members to meet in safe, public places for trades.', '2025-10-23 14:21:12'),
(16, 'Security', 'Is my personal information visible to others?', 'No. Your private details are not shared. All communication happens through ReLeaf\'s secure system.', '2025-10-23 14:21:12'),
(17, 'Support', 'How do I reset my password?', 'Go to Settings > Edit Profile, enter your old password and a new one, then save the changes. Your password will be updated once verified.', '2025-10-23 14:21:12'),
(18, 'Support', 'How do I contact ReLeaf support?', 'Use the in-app Help & Support page in Settings.', '2025-10-23 14:21:12'),
(19, 'Trade', 'How do I start a trade with another user?', 'To start a trade, first send a message to the user you want to trade with. Introduce yourself, and once the conversation is started, click the trade button in the chat (on the left of your message input) to either request one of their listings or offer one of your own listings. The method of trading is flexible (e.g. meeting up to exchange or delivery), discuss how you want to trade with your trading partner!', '2025-10-26 11:00:00'),
(20, 'Trade', 'What happens when I send a trade request?', 'When you send a trade request, the other user will receive a notification in your chat. They can then accept, decline, or let the request expire after 30 days.', '2025-10-26 12:00:00'),
(21, 'Trade', 'Can I cancel a trade request I sent?', 'Yes, you can cancel your own trade requests as long as they haven\'t been accepted yet. Go to the chat where you sent the request and click the \"Cancel\" button on your trade request message.', '2025-10-26 13:00:00'),
(22, 'Trade', 'Can I trade with users in different countries?', 'Yes, you can trade with users worldwide. However, consider shipping costs and local regulations when trading physical items across borders. Always discuss logistics with your trading partner.', '2025-10-26 14:00:00'),
(23, 'General', 'How do I start a conversation with another user?', 'You can start a conversation by visiting a user\'s profile and clicking the chat icon beside their names.', '2025-10-26 16:00:00'),
(24, 'General', 'Can I delete a conversation?', 'Currently, conversations cannot be deleted to maintain a record of trades and communications. This helps protect both parties in case of disputes.', '2025-10-26 17:00:00'),
(25, 'Blog', 'How do I write and publish a blog post?', 'To write a blog, click \"Write A Blog\" on the main blog page. Fill in the title, excerpt, category, content, and add relevant tags. Click \"Publish Blog\" when you\'re ready to share your post with the community.', '2025-10-27 10:00:00'),
(26, 'Blog', 'What should I write about in my blog?', 'Write about sustainability topics like eco-friendly living, gardening tips, renewable energy, conservation efforts, green technology, or personal experiences with environmental initiatives. Share knowledge that can help others live more sustainably.', '2025-10-27 11:00:00'),
(27, 'Blog', 'Are there any content guidelines for blogs?', 'Yes, blogs should be respectful, informative, and related to sustainability. Avoid offensive content, false information, promotional spam, or unrelated topics.', '2025-10-27 11:11:00'),
(28, 'Blog', 'What are tags and how should I use them?', 'Tags help categorize your blog and make it discoverable. Use relevant keywords like \"composting\", \"solar energy\", \"urban gardening\", or \"zero waste\". Choose tags that accurately describe your blog content.', '2025-10-27 15:00:00');

