INSERT INTO `tblmessages` (`messageID`, `conversationID`, `senderID`, `receiverID`, `messageText`, `isRead`, `sentAt`) VALUES
(1, 1, 4, 8, 'Hi Hannah! I saw your succulent arrangement and I\'m interested in trading my Monstera plant for it.', 1, '2025-10-18 10:15:00'),
