INSERT INTO `tbltickets` (`ticketID`, `subject`, `category`, `priority`, `status`, `description`, `userID`, `username`, `userEmail`, `adminAssignedID`, `isUnread`, `createdAt`, `updatedAt`, `lastReplyAt`) VALUES
(1, 'Cannot upload profile picture', 'technical', 'high', 'open', 'I keep getting an error when trying to upload my profile picture. The error says \"File too large\" but my image is only 2MB.', 4, 'Diana Prince', 'diana@example.com', 1, 1, '2025-10-14 02:13:20', '2025-10-20 06:43:50', '2025-10-20 05:25:57'),
(2, 'Account verification issue', 'account', 'medium', 'open', 'I submitted my documents for account verification 3 days ago but still haven\'t received any confirmation. How long does this process usually take?', 5, 'Evan Lee', 'evan@example.com', 2, 1, '2025-10-14 02:13:20', '2025-10-14 02:13:20', '2024-01-15 08:45:00'),
(3, 'Premium subscription payment failed', 'billing', 'urgent', 'open', 'My credit card was charged twice for the premium subscription this month. I only authorized one payment. Please refund the duplicate charge immediately.', 6, 'Fiona Green', 'fiona@example.com', 3, 1, '2025-10-14 02:13:20', '2025-10-14 02:13:20', '2024-01-15 02:15:00'),
(4, 'Feature request: Dark mode', 'feature', 'low', 'in_progress', 'Would love to have a dark mode option for the application, especially for nighttime browsing. This would be really helpful for reducing eye strain.', 7, 'George White', 'george@example.com', 1, 0, '2025-10-14 02:13:20', '2025-10-14 02:13:20', '2024-01-14 10:20:00'),
(5, 'Blog post editing bug', 'bug', 'high', 'in_progress', 'When I try to edit my existing blog posts, the formatting gets messed up. Line breaks disappear and images get displaced. This happens consistently across all my posts.', 8, 'Hannah Black', 'hannah@example.com', 2, 0, '2025-10-14 02:13:20', '2025-10-14 02:13:20', '2024-01-14 07:10:00'),
(6, 'How to reset password?', 'account', 'medium', 'solved', 'I forgot my password and the reset link in my email is not working. It says \"link expired\" even though I just requested it 5 minutes ago.', 9, 'Ian Clark', 'ian@example.com', 3, 0, '2025-10-14 02:13:20', '2025-10-14 02:13:20', '2024-01-13 03:30:00'),
(7, 'Trade item not received', 'general', 'high', 'solved', 'I completed a trade 2 weeks ago but haven\'t received the item. The other user is not responding to my messages. Can you help mediate this situation?', 10, 'Jane Doe', 'jane@example.com', 1, 0, '2025-10-14 02:13:20', '2025-10-14 02:13:20', '2024-01-12 01:45:00'),
(8, 'Event creation guidelines', 'general', 'low', 'closed', 'Where can I find the guidelines for creating events? I want to make sure my event follows all the community rules before posting.', 4, 'Diana Prince', 'diana@example.com', 2, 0, '2025-10-14 02:13:20', '2025-10-14 02:13:20', '2024-01-10 06:20:00'),
(9, 'Mobile app crashing', 'technical', 'urgent', 'closed', 'The mobile app crashes every time I try to open the chat section. I\'m using iPhone 13 with iOS 17.2. This started happening after the latest update.', 5, 'Evan Lee', 'evan@example.com', 3, 0, '2025-10-14 02:13:20', '2025-10-14 02:13:20', '2024-01-08 08:55:00'),
(10, 'General inquiry about points system', 'general', 'low', 'open', 'How does the points system work? I noticed my points increased but I\'m not sure what actions earned them. Is there a breakdown available?', 6, 'Fiona Green', 'fiona@example.com', 1, 1, '2025-10-14 11:46:39', '2025-10-20 04:20:55', NULL),
(11, 'Testing Needed', 'technical', 'low', 'open', 'Test', 31, 'User31', 'testing@gmail.com', 32, 1, '2025-10-25 05:53:28', '2025-10-27 13:19:30', '2025-10-26 02:26:09');

