INSERT INTO `tblticket_responses` (`responseID`, `ticketID`, `responderId`, `responderType`, `message`, `createdAt`) VALUES
(1, 6, 3, 'admin', 'Hello Ian, thank you for contacting support. I understand you\'re having trouble with the password reset link. Let me help you with that.', '2024-01-13 01:15:00'),
(2, 6, 3, 'admin', 'I\'ve just generated a new password reset link and sent it to your email (ian@example.com). This new link will be valid for the next 2 hours. Please check your spam folder if you don\'t see it in your inbox within 5 minutes.', '2024-01-13 01:20:00'),
(3, 6, 9, 'member', 'Thanks! I received the new link and it worked perfectly. I was able to reset my password and log in successfully. Appreciate the quick help!', '2024-01-13 02:05:00'),
(4, 6, 3, 'admin', 'Great to hear that, Ian! I\'m glad we could resolve this quickly. For future reference, password reset links are valid for 1 hour. If you encounter any other issues, don\'t hesitate to reach out. Have a wonderful day!', '2024-01-13 02:10:00'),
(5, 7, 1, 'admin', 'Hi Jane, I\'m sorry to hear about the issue with your trade. I\'ll help mediate this situation for you.', '2024-01-12 01:50:00'),
(6, 7, 1, 'admin', 'I\'ve reviewed the trade history and can see that you traded your \"Vintage Gardening Book\" with user \"plantlover22\" for their \"Herb Seed Collection\" on January 1st. Is this correct?', '2024-01-12 02:30:00'),
(7, 7, 10, 'member', 'Yes, that\'s the correct trade. I shipped my book the next day and provided the tracking number in our chat. The tracking shows it was delivered on January 5th, but I haven\'t received the seeds yet.', '2024-01-12 03:15:00'),
(8, 7, 1, 'admin', 'Thank you for confirming. I\'ve contacted plantlover22 and they mentioned there was a delay due to weather conditions in their area. They provided this tracking number for your seed package: TRK789456123. Let me check the status for you.', '2024-01-12 06:20:00'),
(9, 7, 1, 'admin', 'I checked the tracking and it shows the seeds are out for delivery today! The delay was indeed due to weather-related shipping disruptions in the Midwest region.', '2024-01-12 07:45:00'),
(10, 7, 1, 'admin', 'UPDATE: The tracking shows your seed package was delivered at 3:30 PM today. Could you please confirm if you\'ve received it?', '2024-01-12 08:30:00'),
(11, 7, 10, 'member', 'Yes! I just checked my mailbox and the seeds arrived safely. Thank you so much for your help in resolving this! Everything looks great.', '2024-01-12 09:10:00'),
(12, 7, 1, 'admin', 'Excellent! I\'m glad everything worked out. I\'ve updated both users\' trade reputations to reflect the successful completion. Thank you for your patience throughout this process. Happy gardening!', '2024-01-12 09:15:00');

