CREATE TABLE `tbltrade_listings` (
  `listingID` int(11) NOT NULL,
  `userID` int(11) DEFAULT NULL,
  `title` varchar(255) NOT NULL,
  `description` text NOT NULL,
  `tags` text DEFAULT NULL,
  `imageUrl` varchar(500) DEFAULT NULL,
  `category` enum('Plants','Gardening Tools','Seeds & Saplings','Garden Decor','Gardening Books','Other') DEFAULT 'Plants',
  `dateListed` date NOT NULL,
  `status` enum('active','inactive') DEFAULT 'active',
  `itemType` enum('Plant','Item') DEFAULT 'Plant',
  `itemCondition` enum('New','Excellent','Good','Fair','Poor') DEFAULT 'New',
  `species` varchar(100) DEFAULT NULL,
  `growthStage` varchar(50) DEFAULT NULL,
  `careInstructions` text DEFAULT NULL,
  `brand` varchar(100) DEFAULT NULL,
  `dimensions` varchar(100) DEFAULT NULL,
  `usageHistory` text DEFAULT NULL,
  `lookingFor` text DEFAULT NULL,
  `reported` tinyint(1) DEFAULT 0
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

--
-- Dumping data for table `tbltrade_listings`
