INSERT INTO `tbltrade_listings` (`listingID`, `userID`, `title`, `description`, `tags`, `imageUrl`, `category`, `dateListed`, `status`, `itemType`, `itemCondition`, `species`, `growthStage`, `careInstructions`, `brand`, `dimensions`, `usageHistory`, `lookingFor`, `reported`) VALUES
(1, 4, 'Monstera Deliciosa - Mature Plant', 'Beautiful mature Monstera plant with fenestrated leaves. Well-established and healthy. Looking to trade for gardening tools or other interesting plants. This plant has been growing for over 2 years and is very resilient.', 'monstera, indoor plant, mature, fenestrated', '../../assets/images/placeholder-image.jpg', 'Plants', '2025-01-10', 'inactive', 'Plant', 'Excellent', 'Monstera Deliciosa', 'Mature', 'Bright indirect light, water weekly, prefers humidity', NULL, NULL, NULL, 'gardening tools or other interesting plants', 1),
(2, 5, 'Professional Gardening Tools Set', 'Complete set of professional gardening tools including trowel, pruners, gloves, and weeding tools. Barely used, in excellent condition. Perfect for serious gardeners.', 'tools, gardening, professional, complete set', '../../assets/images/placeholder-image.jpg', 'Gardening Tools', '2025-01-12', 'active', 'Item', 'Excellent', NULL, NULL, NULL, 'Fiskars', 'Tool kit: 12x8x4 inches', 'Used only a few times, like new condition', 'Monstera plant', 1),
(3, 6, 'Heirloom Tomato Seeds Collection', 'Rare heirloom tomato seeds including Brandywine, Cherokee Purple, and Green Zebra varieties. Organic and non-GMO. Perfect for home gardeners.', 'seeds, tomato, heirloom, organic', '../../assets/images/placeholder-image.jpg', 'Seeds & Saplings', '2025-01-08', 'active', 'Item', 'New', NULL, NULL, NULL, NULL, NULL, NULL, 'Monstera plant', 1),
(4, 7, 'Handmade Ceramic Plant Pots', 'Set of 3 beautiful handmade ceramic pots in different sizes. Each piece is unique with natural glaze patterns.', 'pots, ceramic, handmade, decor', '../../assets/images/placeholder-image.jpg', 'Garden Decor', '2025-01-05', 'active', 'Item', 'Good', NULL, NULL, NULL, NULL, NULL, NULL, 'Monstera plant', 0),
(5, 11, 'Organic Herb Seed Collection', 'Assorted organic herb seeds including basil, mint, rosemary, and thyme. Perfect for kitchen gardens.', 'herbs, seeds, organic, kitchen', '../../assets/images/placeholder-image.jpg', 'Seeds & Saplings', '2025-10-20', 'active', 'Item', 'New', 'Mixed Herbs', 'Seeds', 'Plant in well-draining soil, full sun', NULL, NULL, NULL, 'Gardening tools or vegetable seeds', 0),
(6, 12, 'Vintage Watering Can', 'Beautiful vintage-style metal watering can with brass finish. Holds 2 gallons.', 'watering can, vintage, metal, decor', '../../assets/images/placeholder-image.jpg', 'Gardening Tools', '2025-10-18', 'active', 'Item', 'Good', NULL, NULL, 'Hand wash only, avoid harsh chemicals', NULL, NULL, NULL, 'Indoor plants or gardening books', 0),
(7, 13, 'Succulent Arrangement', 'Mixed succulent arrangement in terracotta pot. Low maintenance and drought tolerant.', 'succulents, indoor, arrangement, low-maintenance', '../../assets/images/placeholder-image.jpg', 'Plants', '2025-10-22', 'inactive', 'Plant', 'Excellent', 'Mixed Succulents', 'Mature', 'Bright indirect light, water sparingly', NULL, NULL, NULL, 'Gardening tools or other succulents', 0),
(8, 31, 'Rose', 'A beautiful rose plant.', 'Rose', '../../uploads/tradeListings/trade_1761372127_68fc67df4ddd3.jpg', 'Plants', '2025-10-25', 'active', 'Plant', 'Excellent', 'Rose', 'established', 'Just regular care for plant with enough water and sunlight', '', '', '', 'Looking to trade with jasmine plant in similar condition', 0);

